    }
    setState({ kind: 'loading' });
    const { data, error } = await supabase.functions.invoke<DetailResponse>(
      'get-listing-detail',
      { body: { listing_id: id } },
    );
    if (error) {
      const ctx = (error as { context?: unknown }).context;
      if (
