export function ApplySheet({
  visible,
  listingId,
  listingTitle,
  onDismiss,
  onApplied,
  onServerStateChanged,
}: ApplySheetProps) {
  const { show: showToast } = useToast();
  const [pitch, setPitch] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [keyboardHeight, setKeyboardHeight] = useState(0);

  // Reset the pitch + submitting flags whenever the sheet re-opens, so a prior
  // half-typed message doesn't leak into a fresh attempt.
  useEffect(() => {
    if (visible) {
      setPitch('');
      setSubmitting(false);
    }
  }, [visible]);

  // KeyboardAvoidingView doesn't reliably push content up when nested inside a
  // RN <Modal> (the modal opens its own window so KAV's measured frame and the
  // keyboard's reported frame disagree). Listen to keyboard events directly and
  // apply the height as bottom padding so the CTA stays above the keyboard.
  useEffect(() => {
    const showEvt = Platform.OS === 'ios' ? 'keyboardWillShow' : 'keyboardDidShow';
    const hideEvt = Platform.OS === 'ios' ? 'keyboardWillHide' : 'keyboardDidHide';
    const showSub = Keyboard.addListener(showEvt, (e) => {
      setKeyboardHeight(e.endCoordinates.height);
    });
    const hideSub = Keyboard.addListener(hideEvt, () => setKeyboardHeight(0));
    return () => {
      showSub.remove();
      hideSub.remove();
    };
  }, []);

